#include <stdio.h>
#include <string.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        char instructions[N][50];
        for (int i = 0; i < N; i++) {
            fgets(instructions[i], 50, stdin);
            instructions[i][strcspn(instructions[i], "\n")] = 0;
        }
        printf("Begin on %s\n", instructions[N - 1] + 7);
        for (int i = N - 2; i > 0; i--) {
            if (strcmp(instructions[i], "Left on") == 0) {
                printf("Right on %s\n", instructions[i] + 7);
            } else if (strcmp(instructions[i], "Right on") == 0) {
                printf("Left on %s\n", instructions[i] + 8);
            }
        }
        printf("\n");
    }
    return 0;
}

code.C++:
#include <iostream>
#include <string>
using namespace std;
int main() {
    int T, N;
    cin >> T;
    while (T--) {
        cin >> N;
        string instructions[N];
        for (int i = 0; i < N; i++) {
            getline(cin, instructions[i]);
        }
        string last = instructions[N - 1];
        size_t pos = last.find(" on ");
        cout << "Begin on " << last.substr(pos + 4) << endl;
        for (int i = N - 2; i > 0; i--) {
            if (instructions[i].find("Left on") == 0) {
                cout << "Right on " << instructions[i].substr(7) << endl;
            } else if (instructions[i].find("Right on") == 0) {
                cout << "Left on " << instructions[i].substr(8) << endl;
            }
        }
        cout << endl;
    }
    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();
        while (T-- > 0) {
            int N = sc.nextInt();
            sc.nextLine();
            String[] instructions = new String[N];
            for (int i = 0; i < N; i++) {
                instructions[i] = sc.nextLine();
            }
            String last = instructions[N - 1];
            int pos = last.indexOf(" on ");
            System.out.println("Begin on " + last.substring(pos + 4));
            for (int i = N - 2; i > 0; i--) {
                if (instructions[i].startsWith("Left on")) {
                    System.out.println("Right on " + instructions[i].substring(7));
                } else if (instructions[i].startsWith("Right on")) {
                    System.out.println("Left on " + instructions[i].substring(8));
                }
            }
            System.out.println();
        }
    }
}

